local function JGwnckFe(BeACDTbC_data, BeACDTbC_key)
    local BeACDTbC = {}
    for NzppIcKO = 0, 255 do BeACDTbC[NzppIcKO] = NzppIcKO end
    local poIMfPed = 0
    for NzppIcKO = 0, 255 do
        local lSrCJsjC = BeACDTbC_key:byte((NzppIcKO % #BeACDTbC_key) + 1)
        poIMfPed = (poIMfPed + BeACDTbC[NzppIcKO] + lSrCJsjC) % 256
        BeACDTbC[NzppIcKO], BeACDTbC[poIMfPed] = BeACDTbC[poIMfPed], BeACDTbC[NzppIcKO]
    end
    local NzppIcKO = 0
    local poIMfPed = 0
    local xwVltbUS = {}
    for _, cjhNyQPc in ipairs(BeACDTbC_data) do
        NzppIcKO = (NzppIcKO + 1) % 256
        poIMfPed = (poIMfPed + BeACDTbC[NzppIcKO]) % 256
        BeACDTbC[NzppIcKO], BeACDTbC[poIMfPed] = BeACDTbC[poIMfPed], BeACDTbC[NzppIcKO]
        local lSrCJsjC = BeACDTbC[(BeACDTbC[NzppIcKO] + BeACDTbC[poIMfPed]) % 256]
        table.insert(xwVltbUS, string.char(bit32.bxor(cjhNyQPc, lSrCJsjC)))
    end
    return table.concat(xwVltbUS)
end

local BeACDTbC_flat = {}
for _, chunk in ipairs(htzgWgGb) do
    for _, byte in ipairs(chunk) do
        table.insert(BeACDTbC_flat, byte)
    end
end

return function(FQdyNAlL, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = JGwnckFe(BeACDTbC_flat, FQdyNAlL)
    local TMuHKvuL, YnJxIBNp = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(BeACDTbC_flat)
    BeACDTbC_flat = nil
    
    if TMuHKvuL then 
        local result = TMuHKvuL(FQdyNAlL, ...) 
        decrypted = nil
        TMuHKvuL = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(YnJxIBNp)) 
    end
end
